### async/await vs Promise Chains — Error Handling Patterns

They're equivalent under the hood, but async/await makes certain error-handling patterns much cleaner.

```javascript
// --- Sequential operations ---
// Promise chain
function loadUserData(id) {
  return fetch(`/api/users/${id}`)
    .then(res => {
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return res.json();
    })
    .then(user => fetch(`/api/posts/${user.id}`))
    .then(res => res.json())
    .catch(err => {
      console.error('Failed:', err);
      return null;
    });
}

// async/await — reads like sync code
async function loadUserData2(id) {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const user = await res.json();
    const postsRes = await fetch(`/api/posts/${user.id}`);
    return postsRes.json();
  } catch (err) {
    console.error('Failed:', err);
    return null;
  }
}

// --- Parallel operations — Promise.all is the right tool ---
async function loadDashboard(userId) {
  // Sequential (bad — 3 round trips serially)
  const user = await getUser(userId);
  const posts = await getPosts(userId);
  const settings = await getSettings(userId);

  // Parallel (good — all 3 fire simultaneously)
  const [user2, posts2, settings2] = await Promise.all([
    getUser(userId),
    getPosts(userId),
    getSettings(userId)
  ]);

  return { user2, posts2, settings2 };
}

// --- When Promise chains win: conditional branching ---
// async/await is awkward with conditional branching
function fetchConditional(shouldRetry) {
  return fetch('/api/data')
    .then(res => res.ok ? res.json() : Promise.reject(new Error('failed')))
    .catch(err => shouldRetry ? fetch('/api/fallback').then(r => r.json()) : null);
}

// async/await version is equally clear here:
async function fetchConditional2(shouldRetry) {
  try {
    const res = await fetch('/api/data');
    if (!res.ok) throw new Error('failed');
    return res.json();
  } catch (err) {
    if (shouldRetry) {
      const fallback = await fetch('/api/fallback');
      return fallback.json();
    }
    return null;
  }
}
```

**Common interview trap:** An `async` function that has an unhandled error inside it returns a rejected Promise. If you call it without `await` and without `.catch()`, you get an **unhandled promise rejection** — a common production bug. Always either `await` async function calls inside `try/catch`, or chain `.catch()` at the call site.

