### async/await vs Цепочки Promise — Паттерны обработки ошибок

Под капотом они эквивалентны, но async/await делает определённые паттерны обработки ошибок гораздо чище.

```javascript
// --- Последовательные операции ---
// Цепочка Promise
function loadUserData(id) {
  return fetch(`/api/users/${id}`)
    .then(res => {
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return res.json();
    })
    .then(user => fetch(`/api/posts/${user.id}`))
    .then(res => res.json())
    .catch(err => {
      console.error('Ошибка:', err);
      return null;
    });
}

// async/await — читается как синхронный код
async function loadUserData2(id) {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const user = await res.json();
    const postsRes = await fetch(`/api/posts/${user.id}`);
    return postsRes.json();
  } catch (err) {
    console.error('Ошибка:', err);
    return null;
  }
}

// --- Параллельные операции — Promise.all подходит лучше ---
async function loadDashboard(userId) {
  // Последовательно (плохо — 3 запроса последовательно)
  const user = await getUser(userId);
  const posts = await getPosts(userId);
  const settings = await getSettings(userId);

  // Параллельно (хорошо — все 3 запускаются одновременно)
  const [user2, posts2, settings2] = await Promise.all([
    getUser(userId),
    getPosts(userId),
    getSettings(userId)
  ]);

  return { user2, posts2, settings2 };
}

// --- Когда цепочки Promise лучше: условные ветви ---
function fetchConditional(shouldRetry) {
  return fetch('/api/data')
    .then(res => res.ok ? res.json() : Promise.reject(new Error('failed')))
    .catch(err => shouldRetry ? fetch('/api/fallback').then(r => r.json()) : null);
}

// Версия async/await не менее понятна:
async function fetchConditional2(shouldRetry) {
  try {
    const res = await fetch('/api/data');
    if (!res.ok) throw new Error('failed');
    return res.json();
  } catch (err) {
    if (shouldRetry) {
      const fallback = await fetch('/api/fallback');
      return fallback.json();
    }
    return null;
  }
}
```

**Типичная ошибка на интервью:** `async`-функция с необработанной ошибкой внутри возвращает rejected Promise. Если вы вызываете её без `await` и без `.catch()`, вы получаете **необработанное отклонение промиса** — распространённый баг на проде. Всегда либо `await`-ьте вызовы async-функций внутри `try/catch`, либо добавляйте `.catch()` на месте вызова.

