### Замыкания — Мемоизация и последствия для памяти

```javascript
// Мемоизация: кэширование результатов дорогой функции с помощью замыкания
function memoize(fn) {
  const cache = new Map(); // замкнута возвращаемой функцией
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log('попадание в кэш');
      return cache.get(key);
    }
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

function expensiveCalc(n) {
  let sum = 0;
  for (let i = 0; i <= n; i++) sum += i;
  return sum;
}

const memoCalc = memoize(expensiveCalc);
memoCalc(1000); // вычисляет
memoCalc(1000); // 'попадание в кэш'
memoCalc(2000); // вычисляет (другие аргументы)

// --- Частичное применение с замыканиями ---
function multiply(a, b) { return a * b; }

function partial(fn, ...presetArgs) {
  return function(...laterArgs) {
    return fn(...presetArgs, ...laterArgs);
  };
}

const double = partial(multiply, 2);
const triple = partial(multiply, 3);

console.log(double(5));  // 10
console.log(triple(5)); // 15

// --- Риск утечки памяти ---
const leaks = [];

function leak() {
  const bigArray = new Array(10_000).fill('data'); // большое выделение
  leaks.push(() => bigArray.length); // замыкание держит bigArray живым!
}

leak();
// bigArray не будет собран GC, потому что замыкание в 'leaks' ссылается на него

// Решение: используйте WeakRef если хотите замыкание, но разрешить GC
const weakLeaks = [];
function noLeak() {
  const bigArray = new Array(10_000).fill('data');
  const ref = new WeakRef(bigArray);
  weakLeaks.push(() => ref.deref()?.length ?? 0); // не препятствует GC
}
```

**Типичная ошибка на интервью:** Замыкание удерживает всю внешнюю область видимости живой пока само замыкание существует. Если создавать замыкания внутри обработчиков событий и никогда их не удалять, все захваченные переменные остаются в памяти. Это распространённая причина утечек памяти в долго работающих SPA. Исправление: удалять обработчики событий при размонтировании компонентов, или использовать `WeakRef` когда нужны GC-допустимые ссылки.

