### async/await — Error Handling Gotchas and Patterns

Async/await looks simple, but error handling has several non-obvious traps.

```javascript
// --- Basic error handling ---
async function fetchUser(id) {
  const res = await fetch(`/api/users/${id}`);
  return res.json(); // Note: this can also throw if body isn't valid JSON
}

// Trap 1: fetch doesn't throw on HTTP errors (4xx, 5xx)!
async function safeGet(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
  return res.json();
}

// Trap 2: where you catch determines what you catch
async function outer() {
  try {
    await inner(); // catches errors from inner()
  } catch (e) {
    console.error('outer caught:', e.message);
  }
}

// Trap 3: forgetting await means the error escapes
async function trap() {
  try {
    fetchUser(1); // no await — error is NOT caught by this try/catch!
  } catch (e) {
    console.log('This never runs if fetchUser rejects');
  }
}

// Trap 4: returning a rejected promise doesn't trigger finally correctly
async function tricky() {
  try {
    return Promise.reject(new Error('oops')); // NOT caught by this try!
    // Must be: return await Promise.reject(...);
  } catch (e) {
    console.log('Never reaches here');
  }
}

// Correct pattern: always await in try/catch
async function correct() {
  try {
    return await Promise.reject(new Error('oops')); // caught!
  } catch (e) {
    console.log('Caught:', e.message); // 'Caught: oops'
  }
}

// Trap 5: sequential vs parallel
async function sequential() {
  const a = await op1(); // 1s
  const b = await op2(); // 1s
  // Total: 2s
}

async function parallel() {
  const [a, b] = await Promise.all([op1(), op2()]);
  // Total: 1s (both run simultaneously)
}
```

**Common interview trap:** `return Promise.reject(err)` inside a `try` block is NOT caught by the surrounding `catch` — the Promise rejection propagates outside the async function. You must `return await Promise.reject(err)` (with `await`) to have it caught locally. This is a subtle but impactful difference in error handling chains.

answer.ru:
### async/await — Ловушки и паттерны обработки ошибок

Async/await выглядит просто, но обработка ошибок имеет несколько неочевидных ловушек.

```javascript
// --- Базовая обработка ошибок ---
async function fetchUser(id) {
  const res = await fetch(`/api/users/${id}`);
  return res.json(); // Примечание: это тоже может выбросить если тело не валидный JSON
}

// Ловушка 1: fetch не бросает ошибку при HTTP-ошибках (4xx, 5xx)!
async function safeGet(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
  return res.json();
}

// Ловушка 2: место поимки определяет что поймаете
async function outer() {
  try {
    await inner(); // ловит ошибки из inner()
  } catch (e) {
    console.error('outer поймал:', e.message);
  }
}

// Ловушка 3: забытый await означает что ошибка ускользает
async function trap() {
  try {
    fetchUser(1); // нет await — ошибка НЕ ловится этим try/catch!
  } catch (e) {
    console.log('Это никогда не выполняется если fetchUser отклоняется');
  }
}

// Ловушка 4: возврат rejected Promise не срабатывает с finally корректно
async function tricky() {
  try {
    return Promise.reject(new Error('упс')); // НЕ ловится этим try!
    // Нужно: return await Promise.reject(...);
  } catch (e) {
    console.log('Сюда не доходит');
  }
}

// Корректный паттерн: всегда await в try/catch
async function correct() {
  try {
    return await Promise.reject(new Error('упс')); // поймано!
  } catch (e) {
    console.log('Поймано:', e.message); // 'Поймано: упс'
  }
}

// Ловушка 5: последовательное vs параллельное
async function sequential() {
  const a = await op1(); // 1s
  const b = await op2(); // 1s
  // Итого: 2s
}

async function parallel() {
  const [a, b] = await Promise.all([op1(), op2()]);
  // Итого: 1s (оба выполняются одновременно)
}
```

**Типичная ошибка на интервью:** `return Promise.reject(err)` внутри блока `try` НЕ перехватывается окружающим `catch` — отклонение Promise распространяется за пределы async-функции. Нужно `return await Promise.reject(err)` (с `await`) чтобы перехватить локально. Это тонкое, но значимое различие в цепочках обработки ошибок.

