### `this` in Practice — call, apply, bind, and Borrowing Methods

```javascript
// --- call(thisArg, arg1, arg2) — invoke immediately with specific this ---
const alice = { name: 'Alice', age: 28 };
const bob = { name: 'Bob', age: 35 };

function greet(greeting, punctuation) {
  return `${greeting}, ${this.name}!${punctuation}`;
}

console.log(greet.call(alice, 'Hello', '!'));  // 'Hello, Alice!!'
console.log(greet.call(bob, 'Hi', '?'));       // 'Hi, Bob!?'

// --- apply(thisArg, [args]) — same but args as array ---
console.log(greet.apply(alice, ['Hello', '!'])); // same result

// apply was useful pre-spread for Math.max:
const nums = [3, 1, 4, 1, 5, 9];
console.log(Math.max.apply(null, nums)); // 9
console.log(Math.max(...nums));          // 9 (modern equivalent)

// --- bind(thisArg, ...partialArgs) — returns new function, doesn't call ---
const greetAlice = greet.bind(alice, 'Hello');
console.log(greetAlice('!')); // 'Hello, Alice!!' — 'greeting' already applied
console.log(greetAlice('.')); // 'Hello, Alice!.'

// --- Borrowing methods ---
// Arguments object is array-like — borrow Array methods
function showArgs() {
  const args = Array.prototype.slice.call(arguments);
  // or: Array.from(arguments)
  // or: [...arguments]
  console.log(args.filter(x => x > 2)); // now we have Array methods
}
showArgs(1, 2, 3, 4); // [3, 4]

// Borrow hasOwnProperty safely (target object might override it)
const obj = Object.create(null); // no prototype!
obj.key = 'value';
// obj.hasOwnProperty('key'); // TypeError — no prototype chain!
Object.prototype.hasOwnProperty.call(obj, 'key'); // true — safe borrow

// --- Practical: throttle with bind ---
class Button {
  constructor() {
    this.label = 'Submit';
    // Bind once — stable reference for add/removeEventListener
    this.handleClick = this.handleClick.bind(this);
  }
  handleClick() {
    console.log(`${this.label} clicked`);
  }
  mount(el) { el.addEventListener('click', this.handleClick); }
  unmount(el) { el.removeEventListener('click', this.handleClick); }
}
```

**Common interview trap:** `bind()` returns a **new function** — it doesn't modify the original. Calling `bind` on an already-bound function creates another wrapper but the `this` is locked to the first binding (you can't re-bind a bound function's `this`). Also, for `removeEventListener` to work, you must pass the **same function reference** — calling `.bind()` on every invocation creates different references, so the listener is never actually removed.

