### Closures — Iterator Pattern and Infinite Sequences

```javascript
// Custom iterator using a closure
function range(start, end, step = 1) {
  let current = start;
  return {
    next() {
      if (current > end) return { value: undefined, done: true };
      const value = current;
      current += step;
      return { value, done: false };
    },
    [Symbol.iterator]() { return this; } // make it iterable too
  };
}

const r = range(1, 5);
console.log(r.next()); // { value: 1, done: false }
console.log(r.next()); // { value: 2, done: false }
console.log(r.next()); // { value: 3, done: false }

// Now it works with for...of and spread
const evens = range(0, 10, 2);
for (const n of evens) console.log(n); // 0, 2, 4, 6, 8, 10
console.log([...range(1, 5)]); // [1, 2, 3, 4, 5]

// Infinite sequence
function fibonacci() {
  let [prev, curr] = [0, 1];
  return {
    next() {
      const value = curr;
      [prev, curr] = [curr, prev + curr];
      return { value, done: false }; // never done
    },
    [Symbol.iterator]() { return this; }
  };
}

const fib = fibonacci();
for (let i = 0; i < 8; i++) {
  process.stdout.write(fib.next().value + ' ');
}
// 1 1 2 3 5 8 13 21

// Pipe using closures
function pipe(...fns) {
  return function(initial) {
    return fns.reduce((value, fn) => fn(value), initial);
  };
}

const transform = pipe(
  x => x * 2,
  x => x + 1,
  x => x ** 2
);

console.log(transform(3)); // ((3*2)+1)^2 = 7^2 = 49
```

**Common interview trap:** Each call to `fibonacci()` creates an **independent** sequence — they don't share `prev` and `curr`. This is the fundamental closure guarantee: each function invocation creates a new lexical environment. The iterator protocol (`next()` returning `{value, done}`) is what enables `for...of` and spread to work with custom sequences.

