### Prototype Chain — Inheritance, super, and the Prototype Triangle

```javascript
// --- Prototype triangle: Function, prototype, __proto__ ---
function Foo() {}

// Every function has a 'prototype' property
console.log(typeof Foo.prototype); // 'object'
console.log(Foo.prototype.constructor === Foo); // true

const foo = new Foo();
// foo.__proto__ === Foo.prototype (the prototype chain link)
console.log(Object.getPrototypeOf(foo) === Foo.prototype); // true
console.log(foo instanceof Foo);  // true
console.log(foo.constructor === Foo); // true (inherited from prototype)

// --- Explicit prototype chain setup (pre-class) ---
function Shape(color) {
  this.color = color;
}
Shape.prototype.describe = function() {
  return `A ${this.color} shape`;
};

function Circle(color, radius) {
  Shape.call(this, color); // inherit own properties
  this.radius = radius;
}
// Set up prototype chain: Circle instances → Circle.prototype → Shape.prototype
Circle.prototype = Object.create(Shape.prototype);
Circle.prototype.constructor = Circle; // restore constructor reference

Circle.prototype.area = function() {
  return Math.PI * this.radius ** 2;
};

const c = new Circle('red', 5);
console.log(c.describe()); // 'A red shape' — from Shape.prototype
console.log(c.area());     // 78.53...
console.log(c instanceof Circle); // true
console.log(c instanceof Shape);  // true

// --- Class syntax (same thing, cleaner) ---
class ShapeClass {
  constructor(color) { this.color = color; }
  describe() { return `A ${this.color} shape`; }
}

class CircleClass extends ShapeClass {
  constructor(color, radius) {
    super(color); // must call before accessing 'this'
    this.radius = radius;
  }
  area() { return Math.PI * this.radius ** 2; }
  describe() {
    return super.describe() + ` (circle r=${this.radius})`;
  }
}

const cc = new CircleClass('blue', 3);
console.log(cc.describe()); // 'A blue shape (circle r=3)'

// Prototype chain: cc -> CircleClass.prototype -> ShapeClass.prototype -> Object.prototype -> null
```

**Common interview trap:** In a class constructor that extends another class, you **must** call `super()` before accessing `this`. Forgetting `super()` throws `ReferenceError: Must call super constructor before accessing 'this'`. Also, `Object.create(Shape.prototype)` is used (not `new Shape()`) when setting up manual inheritance, because `new Shape()` would call the constructor with no arguments and potentially cause bugs.

