### Цепь прототипов — Наследование, super и треугольник прототипов

```javascript
// --- Треугольник прототипов: Function, prototype, __proto__ ---
function Foo() {}

// У каждой функции есть свойство 'prototype'
console.log(typeof Foo.prototype); // 'object'
console.log(Foo.prototype.constructor === Foo); // true

const foo = new Foo();
// foo.__proto__ === Foo.prototype (связь цепи прототипов)
console.log(Object.getPrototypeOf(foo) === Foo.prototype); // true
console.log(foo instanceof Foo);  // true
console.log(foo.constructor === Foo); // true (унаследовано от прототипа)

// --- Явная настройка цепи прототипов (до классов) ---
function Shape(color) {
  this.color = color;
}
Shape.prototype.describe = function() {
  return `Фигура цвета ${this.color}`;
};

function Circle(color, radius) {
  Shape.call(this, color); // наследуем собственные свойства
  this.radius = radius;
}
// Настройка цепи: Circle instances → Circle.prototype → Shape.prototype
Circle.prototype = Object.create(Shape.prototype);
Circle.prototype.constructor = Circle; // восстанавливаем ссылку на конструктор

Circle.prototype.area = function() {
  return Math.PI * this.radius ** 2;
};

const c = new Circle('красная', 5);
console.log(c.describe()); // 'Фигура цвета красная' — из Shape.prototype
console.log(c.area());     // 78.53...
console.log(c instanceof Circle); // true
console.log(c instanceof Shape);  // true

// --- Синтаксис класса (то же самое, чище) ---
class ShapeClass {
  constructor(color) { this.color = color; }
  describe() { return `Фигура цвета ${this.color}`; }
}

class CircleClass extends ShapeClass {
  constructor(color, radius) {
    super(color); // нужно вызвать до обращения к 'this'
    this.radius = radius;
  }
  area() { return Math.PI * this.radius ** 2; }
  describe() {
    return super.describe() + ` (круг r=${this.radius})`;
  }
}

const cc = new CircleClass('синяя', 3);
console.log(cc.describe()); // 'Фигура цвета синяя (круг r=3)'

// Цепь прототипов: cc -> CircleClass.prototype -> ShapeClass.prototype -> Object.prototype -> null
```

**Типичная ошибка на интервью:** В конструкторе класса, расширяющего другой, **нужно** вызвать `super()` до обращения к `this`. Забытый `super()` бросает `ReferenceError: Must call super constructor before accessing 'this'`. Также `Object.create(Shape.prototype)` используется (не `new Shape()`) при ручной настройке наследования, потому что `new Shape()` вызовет конструктор без аргументов и может вызвать баги.

answer.en:
### async/await — The async IIFE, Top-Level await, and Concurrent Patterns

```javascript
// --- async IIFE: run async code without a wrapping async function ---
(async function() {
  const data = await fetch('/api').then(r => r.json());
  console.log(data);
})();

// Arrow IIFE equivalent:
(async () => {
  const data = await fetch('/api').then(r => r.json());
  console.log(data);
})();

// --- Top-level await (ES modules only) ---
// In a .mjs file or <script type="module">:
const config = await fetch('/config').then(r => r.json());
export const apiUrl = config.apiUrl; // module-level constant from async data

// --- Await in different contexts ---
// Works: inside async function
async function main() {
  const a = await Promise.resolve(1);
  return a + 1;
}

// Works: top-level in ES module
// const a = await Promise.resolve(1); // module-level

// Doesn't work: regular function body
// function broken() { await Promise.resolve(1); } // SyntaxError

// --- Concurrent patterns ---
// 1. Parallel with Promise.all
async function loadAll(ids) {
  return Promise.all(ids.map(id => fetchUser(id)));
}

// 2. Parallel with settled results
async function loadAllSafe(ids) {
  const results = await Promise.allSettled(ids.map(id => fetchUser(id)));
  return results
    .filter(r => r.status === 'fulfilled')
    .map(r => r.value);
}

// 3. Sequential with async generator (for streaming)
async function* loadSequentially(ids) {
  for (const id of ids) {
    yield await fetchUser(id); // one at a time
  }
}

for await (const user of loadSequentially([1, 2, 3])) {
  console.log(user); // processes each as it arrives
}

// 4. Rate-limited concurrency
async function limitedParallel(tasks, limit) {
  const results = [];
  for (let i = 0; i < tasks.length; i += limit) {
    const batch = tasks.slice(i, i + limit);
    const batchResults = await Promise.all(batch.map(t => t()));
    results.push(...batchResults);
  }
  return results;
}
```

**Common interview trap:** `async/await` doesn't make JS multi-threaded — it's still single-threaded. `await` pauses the **current async function** only, not the entire event loop. Other callbacks and events continue to be processed during an `await`. This is why `await` is fundamentally different from a synchronous `sleep()` that would block everything.

