    .filter(r => r.status === 'fulfilled')
    .map(r => r.value);
}

// 3. Последовательно с async-генератором (для стриминга)
async function* loadSequentially(ids) {
  for (const id of ids) {
    yield await fetchUser(id); // по одному за раз
  }
}

for await (const user of loadSequentially([1, 2, 3])) {
  console.log(user); // обрабатывает по мере поступления
}

// 4. Конкурентность с ограниченным числом
async function limitedParallel(tasks, limit) {
  const results = [];
  for (let i = 0; i < tasks.length; i += limit) {
    const batch = tasks.slice(i, i + limit);
