### AbortController — Общие сигналы, Timeout API и пользовательские операции

```javascript
// --- Отмена нескольких запросов одним сигналом ---
async function loadDashboard(userId) {
  const controller = new AbortController();
  const { signal } = controller;

  // Очистка: отменить все запросы если компонент размонтирован
  const cleanup = () => controller.abort('Пользователь покинул страницу');

  try {
    const [user, posts, settings] = await Promise.all([
      fetch(`/api/users/${userId}`, { signal }).then(r => r.json()),
      fetch(`/api/users/${userId}/posts`, { signal }).then(r => r.json()),
      fetch(`/api/settings`, { signal }).then(r => r.json()),
    ]);
    return { user, posts, settings };
  } catch (err) {
    if (err.name === 'AbortError') {
      console.log('Загрузка дашборда отменена:', signal.reason);
      return null;
    }
    throw err;
  }

  return cleanup; // вызывающий может вызвать это для отмены
}

// --- AbortSignal.timeout (Node 17+, браузеры 2023) ---
try {
  const response = await fetch('/api/slow', {
    signal: AbortSignal.timeout(5000) // авто-отмена через 5 секунд
  });
  const data = await response.json();
} catch (err) {
  if (err.name === 'TimeoutError') console.log('Запрос превысил время');
  else throw err;
}

// --- Пользовательская async-операция, учитывающая AbortSignal ---
function delay(ms, signal) {
  return new Promise((resolve, reject) => {
    if (signal?.aborted) return reject(signal.reason);

    const timer = setTimeout(resolve, ms);

    signal?.addEventListener('abort', () => {
      clearTimeout(timer);
      reject(signal.reason);
    }, { once: true });
  });
}

const ctrl = new AbortController();
delay(10000, ctrl.signal)
  .then(() => console.log('выполнено'))
  .catch(err => console.log('отменено:', err));

setTimeout(() => ctrl.abort('слишком медленно'), 2000);
// 'отменено: слишком медленно' через 2 секунды вместо ожидания 10
```

**Типичная ошибка на интервью:** Вызов `abort()` сам по себе синхронный — он устанавливает `signal.aborted = true` и диспатчит событие `abort`. Но у fetch ещё есть ожидающий сетевой I/O; он отклоняется только когда браузер отменяет базовый запрос. Также можно передать причину отмены в `controller.abort(reason)` (доступна как `signal.reason`) — полезно для различения таймаута, действия пользователя и навигации.

