### Generator Delegation — yield* and Composable Sequences

`yield*` delegates to any iterable — another generator, an array, a string, or a Set.

```javascript
// --- Basic yield* delegation ---
function* numbers() { yield 1; yield 2; }
function* letters() { yield 'a'; yield 'b'; }

function* combined() {
  yield* numbers(); // delegates: yields 1, 2
  yield* letters(); // delegates: yields 'a', 'b'
  yield* [10, 20];  // also works with plain arrays
}

console.log([...combined()]); // [1, 2, 'a', 'b', 10, 20]

// --- yield* passes through the return value ---
function* inner() {
  yield 1;
  yield 2;
  return 'inner done'; // return value, not yielded
}

function* outer() {
  const result = yield* inner(); // result captures return value
  console.log('inner returned:', result); // 'inner done'
  yield 3;
}

console.log([...outer()]); // [1, 2, 3] — 'inner done' is NOT in the sequence

// --- Flatten arbitrary depth with generators ---
function* flatten(iterable) {
  for (const item of iterable) {
    if (item != null && typeof item[Symbol.iterator] === 'function' && typeof item !== 'string') {
      yield* flatten(item);
    } else {
      yield item;
    }
  }
}

const nested = [1, [2, [3, [4]], 5], 6];
console.log([...flatten(nested)]); // [1, 2, 3, 4, 5, 6]

// --- Composable lazy pipeline ---
function* range(start, end) {
  for (let i = start; i <= end; i++) yield i;
}

function* take(n, iterable) {
  let count = 0;
  for (const item of iterable) {
    if (count++ >= n) break;
    yield item;
  }
}

function* mapGen(fn, iterable) {
  for (const item of iterable) yield fn(item);
}

function* filterGen(pred, iterable) {
  for (const item of iterable) if (pred(item)) yield item;
}

// Lazy: only computes values needed
const result = take(3,
  filterGen(x => x % 2 === 0,
    mapGen(x => x * x,
      range(1, 100)
    )
  )
);

console.log([...result]); // [4, 16, 36] — only evaluated what was needed
```

**Common interview trap:** `yield*` delegates **iteration**, not the return value. The return value of an inner generator is captured as the expression value of `yield*`, but is NOT emitted as a yielded item to the outer consumer. Many developers expect `yield* gen()` to pass through the inner generator's `return 'value'` to the sequence — it does not.

