### AbortController — Custom Signal-Aware Operations and AbortSignal.any()

```javascript
// --- Making any async operation cancellable ---
async function retryWithAbort(fn, { retries = 3, delay = 1000, signal } = {}) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    // Check before starting each attempt
    if (signal?.aborted) throw signal.reason ?? new Error('Aborted');

    try {
      return await fn(signal);
    } catch (err) {
      if (err.name === 'AbortError') throw err; // don't retry on abort
      if (attempt === retries) throw err;

      // Cancellable delay between retries
      await new Promise((resolve, reject) => {
        const timer = setTimeout(resolve, delay);
        signal?.addEventListener('abort', () => {
          clearTimeout(timer);
          reject(signal.reason);
        }, { once: true });
      });
    }
  }
}

const controller = new AbortController();

retryWithAbort(
  (signal) => fetch('/api/flaky', { signal }).then(r => r.json()),
  { retries: 3, delay: 2000, signal: controller.signal }
).then(console.log).catch(err => console.log('Failed:', err.message));

// Cancel from outside after 5 seconds:
setTimeout(() => controller.abort(new Error('User cancelled')), 5000);

// --- AbortSignal.any(): abort when ANY signal fires ---
// (Node 20+, Chrome 116+)
const userCancel = new AbortController();
const timeout = AbortSignal.timeout(10000);
const combined = AbortSignal.any([userCancel.signal, timeout]);

fetch('/api/data', { signal: combined })
  .then(r => r.json())
  .then(console.log)
  .catch(err => {
    if (err.name === 'TimeoutError') console.log('Timed out after 10s');
    else if (err.name === 'AbortError') console.log('User cancelled');
  });

// Fires on whichever happens first: user cancel or 10s timeout
userCancel.abort(); // or: just wait 10 seconds
```

**Common interview trap:** When `abort()` fires, the `abort` event listener added to the signal runs **synchronously** (as an event dispatch). But `fetch` rejection is asynchronous — the underlying request still needs to be torn down. This means in the `catch` block, `signal.aborted` is already `true`, but the fetch may have already started transferring data. Always check `err.name === 'AbortError'` rather than assuming timing.

