### WeakMap for Memoization and WeakSet for Cycle Detection

```javascript
// --- Memoization with WeakMap (object arguments) ---
// Regular memoization with Map leaks memory if object arguments are transient
const memoCache = new WeakMap();

function memoize(fn) {
  return function(arg) {
    // Only works for object arguments (WeakMap key must be object)
    if (typeof arg !== 'object' || arg === null) return fn(arg);

    if (memoCache.has(arg)) {
      console.log('cache hit');
      return memoCache.get(arg);
    }
    const result = fn(arg);
    memoCache.set(arg, result);
    return result;
  };
}

const expensiveCalc = memoize((config) => {
  // expensive computation based on config object
  return config.values.reduce((sum, n) => sum + n, 0);
});

const cfg1 = { values: [1, 2, 3, 4, 5] };
console.log(expensiveCalc(cfg1)); // 15
console.log(expensiveCalc(cfg1)); // cache hit → 15
// When cfg1 goes out of scope, WeakMap entry is GC'd — no leak

// --- WeakSet for cycle detection in deep clone ---
function deepClone(obj, seen = new WeakSet()) {
  if (obj === null || typeof obj !== 'object') return obj;

  if (seen.has(obj)) {
    throw new Error('Circular reference detected');
  }
  seen.add(obj);

  if (Array.isArray(obj)) {
    return obj.map(item => deepClone(item, seen));
  }

  const clone = {};
  for (const [key, value] of Object.entries(obj)) {
    clone[key] = deepClone(value, seen);
  }
  return clone;
}

const a = { x: 1, nested: { y: 2 } };
console.log(deepClone(a)); // { x: 1, nested: { y: 2 } }

const circular = { name: 'circle' };
circular.self = circular; // circular reference
try {
  deepClone(circular);
} catch (e) {
  console.log(e.message); // 'Circular reference detected'
}

// Why WeakSet and not Set? If the original objects are temporary,
// using Set would prevent their GC during the clone operation.
// With WeakSet, once deepClone returns, the seen set no longer
// holds references to processed objects.
```

**Common interview trap:** The `WeakSet` in `deepClone` is created fresh per call — it's not a global cache. This means different calls don't interfere. But if you made it a closure variable shared across calls, objects from one clone wouldn't be visible to another, which is actually what you want. The key insight: `WeakSet` tracks *identity* (reference equality), not value equality, so `{ x: 1 }` and `{ x: 1 }` are two separate entries.

